queries.sparql:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?savings_accounts a :SavingsAccounts .
    ?savings_accounts p:AccountNumber ?accountnumber .
    BIND(?accountnumber AS ?o0)
  }
  UNION
  {
    ?checking_accounts a :CheckingAccounts .
    ?checking_accounts p:AccountNumber ?accountnumber .
    ?checking_accounts p:Interest_Rate ?interest_rate_f .
    FILTER(STR(?interest_rate_f) = "1%")
    BIND(?accountnumber AS ?o0)
  }
}

